args.sparql:
SELECT ?club ?manager
WHERE {
  wd:Q27265416 wdt:P1545 ?club.
  ?club wdt:P17 wd:Q141.
  ?club wdt:P210 ?stadium.
  ?stadium wdt:P1198 ?capacity.
  FILTER(?capacity = 3000)
  ?club wdt:P1958 ?manager.
  SERVICE wikibase:label { bd:serviceParam wikibase:language "en". }
}

SELECT ?manager
WHERE {
  wd:Q2180767 wdt:P1958 ?manager;
            wdt:P210 ?stadium.
  ?stadium wdt:P1198 ?capacity.
  FILTER(?capacity = 3000)
}
